<?php require 'config/config.php'; require 'config/Database.php'; $db = Database::getInstance(); $db->query('SELECT pa.*, a.nombre_ambiente as ambiente_nombre, u.nombre as instructor_nombre, u.apellido as instructor_apellido, c.nombre as competencia_nombre, ra.descripcion as ra_descripcion FROM programacion_academica pa LEFT JOIN ambientes a ON pa.id_numero_ambiente = a.id_numero_ambiente LEFT JOIN usuarios u ON pa.id_usuario = u.id_usuario LEFT JOIN resultados_aprendizaje ra ON pa.id_resultado_aprendizaje = ra.id_resultado_aprendizaje LEFT JOIN competencias c ON ra.id_competencia = c.id_competencia WHERE pa.id_numero_ambiente = 1'); print_r($db->resultSet()); ?>
